onClick:
{{
  (async () => {
    try {
      const code = inp_MaCongCu.text ? inp_MaCongCu.text.trim() : "";
      const qty = Number(inp_SoLuong.text);

      if (!code || qty <= 0) {
        return showAlert("⚠️ Vui lòng nhập Mã và Số lượng!", "warning");
      }

      // 1. Chạy Query xuất kho
      await Action_Export_Tool_Full.run({
        code: code,
        qty: qty,
        emp: sel_NhanVien.selectedOptionValue,
        urg: sel_KhanCap.selectedOptionValue,
        mach: inp_MaySuDung.text,
        note: inp_GhiChu.text
      });

      // 2. Làm mới TẤT CẢ các bảng liên quan cùng lúc (Tối ưu tốc độ)
      await Promise.all([
        Get_Bang_Tool.run(),       // Bảng Kho chính
        Get_LS_Xuat.run(),         // Bảng Lịch sử xuất
        Get_Inventory_Data.run()          // <--- THAY TÊN QUERY CỦA BẢNG KIỂM KÊ VÀO ĐÂY
      ]);

      // 3. Xóa dữ liệu nhập
      inp_MaCongCu.setValue("");
      inp_SoLuong.setValue("");
      inp_GhiChu.setValue("");

      showAlert("✅ Xuất kho thành công và cập nhật dữ liệu!", "success");

    } catch (err) {
      console.error("Lỗi:", err);
      showAlert("❌ Lỗi: " + err.message, "error");
    }
  })()
}}
